            ContentJson = """{"appRoute":"/payables","startButtonLabel":"Tour Payables","steps":[{"element":".tab-bar","popover":{"title":"Payables Tabs","description":"The page is split into tabs. Bills are vendor invoices you owe. Payments is money you send to vendors. Batches and Accounts handle bank payments. You will spend most of your time on Bills and Payments.","side":"bottom"}},{"element":"[data-testid='new-vendor-bill-btn']","popover":{"title":"New Bill Button","description":"Click here on the Bills tab to enter a vendor invoice. Pick the vendor, set the bill and due dates, and add lines. You can type lines yourself or pull them from a purchase order. New bills start as a Draft.","side":"bottom"}},{"element":".filters-bar app-select","popover":{"title":"Vendor and Status Filters","description":"Narrow the list by vendor and by status. On the Bills tab, filter by Draft, Approved, Partially Paid, Paid, or Void. On the Payments tab, filter by payment method and transmission status instead.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Bills Table","description":"Each row is a vendor bill. You see its number, vendor, status, dates, and amounts, with the balance due highlighted when money is still owed. Click any row to open the bill and see its detail.","side":"top"}},{"element":"[data-testid='new-vendor-payment-btn']","popover":{"title":"New Payment Button","description":"Switch to the Payments tab and click here to record a payment. Choose the vendor, and the panel loads that vendor's open bills. Enter how much of the payment to apply to each one.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Bill Detail Panel","description":"Open a bill to see its detail: its status, vendor, linked purchase order, line items, and totals. The buttons you see depend on the status. Approve a Draft bill, or void a Draft or Approved bill when nothing has been paid yet.","side":"top"}},{"element":"app-data-table","popover":{"title":"Payment Detail Panel","description":"Open a payment to see its detail: the vendor, method, amount, and which bills it was applied to. For electronic payments you also see the bank status, with buttons to retry a failed send, confirm a queued wire, or reverse the payment.","side":"top"}}]}"""
