            Tags = """["payables","ap","accounting","reference"]""",
            ContentJson = """{"title":"Payables Field Reference","groups":[{"heading":"Vendor Bill Form Fields (New Bill)","items":[{"label":"Vendor (required)","value":"Pick the vendor this bill is owed to. Only active vendors are listed."},{"label":"Vendor Invoice # (optional)","value":"The vendor's own invoice number. It shows in the list, or a dash when left blank."},{"label":"Bill Date (required)","value":"The date on the vendor's invoice. Cannot be in the future."},{"label":"Due Date (required)","value":"The date the payment is due."},{"label":"Tax Amount (optional)","value":"Tax on the bill, added on top of the line subtotal. Starts at zero."},{"label":"Currency (multi-currency installs)","value":"The bill's currency. Only appears when more than one currency is set up; otherwise your default currency is used."},{"label":"FX Rate (non-base currency)","value":"The exchange rate back to your default currency. Only appears when you pick a different currency."},{"label":"From Purchase Order (on/off switch)","value":"Turn on to bill against a purchase order instead of typing lines by hand."},{"label":"Purchase Order (PO mode)","value":"The purchase order to bill against. Required once From Purchase Order is on."},{"label":"Notes (optional)","value":"Free-form notes about the bill."}]},{"heading":"Bill Line Item Fields","items":[{"label":"Part (typed lines, optional)","value":"Optionally link the line to a part. You can search by part number or name."},{"label":"Description (typed lines, required)","value":"What the line is for. Required on each line you type by hand."},{"label":"Quantity (typed lines, required)","value":"How many. Must be greater than zero."},{"label":"Unit Price (typed lines, required)","value":"Price per unit. Cannot be negative."},{"label":"Add Line (typed lines)","value":"Adds another line you type by hand."},{"label":"Quantity to Bill (PO mode, required)","value":"How much of the PO line to bill. Cannot exceed what was received but not yet billed."},{"label":"Unit Price (PO mode, required)","value":"Price per unit, pre-filled from the purchase order. You can change it if the invoice differs."}]},{"heading":"Vendor Bill Statuses","items":[{"label":"Draft (blue)","value":"Entered but not yet approved. This is where every new bill starts. You can approve it or void it."},{"label":"Approved (teal)","value":"Approved for payment. You can now apply payments to it, and it can still be voided if nothing is paid."},{"label":"Partially Paid (amber)","value":"Approved and partly paid off. Some balance is still owed."},{"label":"Paid (green)","value":"Fully paid off. Nothing is owed. This is the end of the road."},{"label":"Void (gray)","value":"Cancelled before payment. This is the end of the road."},{"label":"From Expense (blue)","value":"This bill was created automatically from an approved expense. Bills like this cannot be voided here."},{"label":"Payment Failed (red)","value":"Shows on a bill when an electronic payment for it failed to send."}]},{"heading":"Vendor Payment Form Fields (New Payment)","items":[{"label":"Vendor (required)","value":"Pick the vendor you are paying. Only active vendors are listed. Choosing one loads that vendor's open bills."},{"label":"Method (required)","value":"How you are paying: Cash, Check, Credit Card, Bank Transfer, Wire, or Other."},{"label":"Amount (required)","value":"The total amount you are paying. Must be at least one cent."},{"label":"Payment Date (required)","value":"The date of the payment. Cannot be in the future."},{"label":"Reference # (optional)","value":"A reference such as a check number or wire reference."},{"label":"Amount to Apply (per bill)","value":"How much of the payment goes to each bill. Cannot exceed what that bill still owes."},{"label":"Settlement FX Rate (per bill, multi-currency)","value":"The exchange rate for each bill, shown only when more than one currency is in use."},{"label":"Notes (optional)","value":"Free-form notes about the payment."}]},{"heading":"Payment Methods","items":[{"label":"Cash","value":"A cash payment."},{"label":"Check","value":"A paper check. The check number usually goes in the Reference field."},{"label":"Credit Card","value":"A credit card payment."},{"label":"Bank Transfer","value":"An electronic ACH transfer. Its progress to the bank is tracked."},{"label":"Wire","value":"A wire transfer. Its progress is tracked, and while queued a second person must confirm it."},{"label":"Other","value":"Any method not listed above."}]},{"heading":"Payment Transmission Statuses (Electronic Payments)","items":[{"label":"Queued (blue)","value":"Waiting to be sent. A wire must be confirmed by a second person while it sits here."},{"label":"Retrying (amber)","value":"A send failed and another attempt is scheduled. Shows how many tries and when the next one is."},{"label":"Succeeded (green)","value":"Sent successfully. A confirmation reference is recorded."},{"label":"Failed (red)","value":"Every attempt failed. A banner appears and you can retry the send."},{"label":"Cancelled (gray)","value":"The send was cancelled."}]},{"heading":"Bill Detail Buttons and Actions","items":[{"label":"Approve Bill","value":"Approves a Draft bill so it can be paid. Only shows on a Draft. Asks you to confirm first."},{"label":"Void Bill","value":"Cancels a bill. Only shows on a Draft or Approved bill, only when nothing has been paid and the bill did not come from an expense. Asks you to confirm first."},{"label":"Save / Create Bill","value":"Creates the bill. Stays disabled until the form is filled in correctly with at least one line."}]},{"heading":"Payment Detail Buttons and Actions","items":[{"label":"Retry Transmission","value":"Tries a failed electronic payment again. Only shows when the send failed."},{"label":"Attest Wire","value":"A second person confirms and releases a wire so it can send. Only shows on a queued wire."},{"label":"Void Payment","value":"Reverses a payment. Asks you for a reason and to confirm."},{"label":"Save / Create Payment","value":"Creates the payment and applies it to the bills. Stays disabled until the form is correct and not over-applied."}]},{"heading":"Validation Rules","items":[{"label":"Bill — Vendor","value":"Required. Pick an active vendor."},{"label":"Bill — Bill Date","value":"Required. Must be today or earlier."},{"label":"Bill — Due Date","value":"Required."},{"label":"Bill — Line Items","value":"At least one line is required. Typed lines each need a description, a quantity above zero, and a price that is not negative."},{"label":"Bill — From Purchase Order","value":"When on, a purchase order is required and each line's quantity cannot exceed what was received but not yet billed."},{"label":"Bill — Save disabled when","value":"The form is incomplete, there are no lines, or a save is already in progress."},{"label":"Payment — Vendor, Method, Amount, Date","value":"All required. The amount must be at least one cent, and the date must be today or earlier."},{"label":"Payment — Applications","value":"What you apply to each bill cannot exceed what it owes, and the total applied cannot exceed the payment amount."},{"label":"Payment — Save disabled when","value":"The form is incomplete, the payment is over-applied, or a save is already in progress."}]},{"heading":"Bills Table Columns","items":[{"label":"Bill Number","value":"The bill's number, generated for you. You can sort by it."},{"label":"Vendor","value":"The vendor name. You can sort by it."},{"label":"Vendor Invoice #","value":"The vendor's own reference, or a dash when blank. You can sort by it."},{"label":"Status","value":"A colored label showing where the bill stands. You can sort and filter by it: Draft, Approved, Partially Paid, Paid, or Void."},{"label":"Bill Date","value":"The invoice date. You can sort by it."},{"label":"Due Date","value":"When payment is due. You can sort by it."},{"label":"Total","value":"The bill total. You can sort by it."},{"label":"Paid","value":"How much has been paid so far. You can sort by it."},{"label":"Balance Due","value":"What is still owed, highlighted when above zero. You can sort by it."}]},{"heading":"Payments Table Columns","items":[{"label":"Payment #","value":"The payment's number, generated for you. You can sort by it."},{"label":"Vendor","value":"The vendor name. You can sort by it."},{"label":"Method","value":"How the payment was made. You can sort and filter by it."},{"label":"Amount","value":"The payment amount. You can sort by it."},{"label":"Applied","value":"How much has been applied to bills. You can sort by it."},{"label":"Unapplied","value":"How much is not yet applied, highlighted when above zero. You can sort by it."},{"label":"Payment Date","value":"The payment date. You can sort by it."},{"label":"Reference #","value":"The check or wire reference. You can sort by it."},{"label":"Transmission Status","value":"A colored label showing an electronic payment's progress to the bank, or a dash when it does not apply. You can sort and filter by it."}]}]}"""
