            AppRoutes = """["/payables"]""",
            Tags = """["payables","ap","accounting","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"pa1","text":"A vendor invoice just arrived. What is the first step to record it in Payables?","options":[{"id":"a","text":"Go to Purchase Orders and mark the PO as billed"},{"id":"b","text":"On the Bills tab, click New Bill, select the vendor, set the bill and due dates, add line items, and save","isCorrect":true},{"id":"c","text":"Record a payment first and the bill is created automatically"},{"id":"d","text":"Create the bill from the Vendors page under a Billing tab"}],"explanation":"Vendor bills are entered from the Bills tab. Click New Bill, pick the vendor, set the Bill Date and Due Date, add line items (standalone or From Purchase Order), and save. New bills start in Draft status."},{"id":"pa2","text":"What is the correct lifecycle of a vendor bill?","options":[{"id":"a","text":"Open → Processing → Closed"},{"id":"b","text":"Draft → Approved → Partially Paid → Paid (or Void from Draft/Approved)","isCorrect":true},{"id":"c","text":"Pending → Sent → Received → Settled"},{"id":"d","text":"Entered → Posted → Reconciled"}],"explanation":"A bill starts in Draft, becomes payable when you approve it, then moves to Partially Paid and Paid as payments are applied. A bill can be voided only while it is Draft or Approved."},{"id":"pa3","text":"When does a Draft bill become payable — ready to have payments applied to it?","options":[{"id":"a","text":"As soon as it is saved in Draft"},{"id":"b","text":"When you approve it with the Approve Bill button (only shown on a Draft)","isCorrect":true},{"id":"c","text":"Only after it is fully paid"},{"id":"d","text":"Bills are never payable in this module"}],"explanation":"A Draft bill is just entered — you cannot pay it yet. Approving it makes it payable and starts it aging toward its due date. Use the Approve Bill button, which shows only on a Draft."},{"id":"pa4","text":"You want to bill against a Purchase Order. What constrains how much you can bill on each line?","options":[{"id":"a","text":"The ordered quantity on the PO"},{"id":"b","text":"The received-but-unbilled quantity (three-way matching)","isCorrect":true},{"id":"c","text":"There is no limit; you can bill any quantity"},{"id":"d","text":"The vendor's credit limit"}],"explanation":"With the From Purchase Order switch on, each line's Quantity to Bill cannot exceed the quantity received but not yet billed. This is three-way matching."},{"id":"pa5","text":"How does a vendor payment get applied to bills?","options":[{"id":"a","text":"It automatically pays the oldest bill in full with no choices"},{"id":"b","text":"After selecting the vendor, the panel loads that vendor's open bills (Approved or Partially Paid) and you enter how much to apply to each","isCorrect":true},{"id":"c","text":"Payments cannot be applied to bills; they are separate records"},{"id":"d","text":"You must approve each application from the bill detail later"}],"explanation":"When you pick a vendor on a new payment, the panel loads that vendor's open bills (Approved or Partially Paid). You enter an amount to apply per bill, and each cannot exceed what that bill still owes. Applying the payment moves bills to Partially Paid or Paid."},{"id":"pa6","text":"On a new payment, what does the Unapplied amount represent?","options":[{"id":"a","text":"The tax portion of the payment"},{"id":"b","text":"The part of the payment amount not yet applied to any bill","isCorrect":true},{"id":"c","text":"The amount the vendor still owes you"},{"id":"d","text":"A required deposit that must equal zero"}],"explanation":"Unapplied is the payment amount minus the total applied across bills. It is highlighted when greater than zero. The total applied may not exceed the payment amount, or the payment is over-applied and Save is disabled."},{"id":"pa7","text":"Which conditions must all be true to void a vendor bill?","options":[{"id":"a","text":"The bill must be Paid"},{"id":"b","text":"The bill is Draft or Approved, nothing has been paid against it, and it did not come from an expense","isCorrect":true},{"id":"c","text":"Any bill can be voided at any time"},{"id":"d","text":"Only bills with a linked Purchase Order can be voided"}],"explanation":"Void Bill is available only from Draft or Approved status, only when the amount paid is zero, and only when the bill did not come from an expense. A bill you have already paid against cannot be voided — reverse the payment first."},{"id":"pa8","text":"An electronic payment shows a Failed transmission status. What can you do?","options":[{"id":"a","text":"Nothing; you must delete it and start over"},{"id":"b","text":"Open the payment detail and click Retry Transmission","isCorrect":true},{"id":"c","text":"Change its method to Cash to clear the error"},{"id":"d","text":"Wait; failed transmissions retry indefinitely on their own"}],"explanation":"A failed transmission surfaces a banner and enables the Retry Transmission button on the payment detail. Bank Transfer and Wire payments carry a transmission status (Queued, Retrying, Succeeded, Failed, Cancelled)."},{"id":"pa9","text":"What extra step does a Wire payment require before it transmits?","options":[{"id":"a","text":"Nothing different from a Bank Transfer"},{"id":"b","text":"While the wire is Queued, a second user must Attest Wire (dual control)","isCorrect":true},{"id":"c","text":"The vendor must confirm receipt first"},{"id":"d","text":"It must be split into multiple smaller payments"}],"explanation":"Wire payments add a dual-control step: while the transmission is Queued, the Attest Wire button lets a second user confirm and release the wire before it sends."},{"id":"pa10","text":"What is required to save a new vendor bill?","options":[{"id":"a","text":"Only a vendor selection"},{"id":"b","text":"A vendor, a Bill Date (today or earlier), a Due Date, and at least one valid line item","isCorrect":true},{"id":"c","text":"A vendor, a tax amount, and notes"},{"id":"d","text":"A linked Purchase Order in every case"}],"explanation":"Save is disabled until the form is valid and at least one active line exists. Required fields are Vendor, Bill Date (max today), and Due Date; standalone lines need a description, quantity, and unit price. A PO is required only when From Purchase Order is on."},{"id":"pa11","text":"A bill row shows a 'From Expense' label. What does that tell you?","options":[{"id":"a","text":"The bill is overdue"},{"id":"b","text":"The bill was created automatically from a vendor-settled expense and cannot be voided","isCorrect":true},{"id":"c","text":"The bill has no line items"},{"id":"d","text":"The bill was imported from an outside accounting package"}],"explanation":"A 'From Expense' label means the bill was created automatically when a vendor-paid expense was approved. One consequence is that such bills cannot be voided here."},{"id":"pa12","text":"How do the vendor and status filters at the top of the page behave?","options":[{"id":"a","text":"They only affect the Batches tab"},{"id":"b","text":"The vendor filter scopes the visible rows, and the status filter offers status options appropriate to the active tab (bill statuses on Bills, method/transmission on Payments)","isCorrect":true},{"id":"c","text":"They permanently delete rows that do not match"},{"id":"d","text":"They are read-only and only display the current vendor"}],"explanation":"The vendor filter narrows rows to one vendor (All Vendors by default). The status filter adapts to the tab: the Bills tab filters by bill status (Draft, Approved, Partially Paid, Paid, Void), while the Payments tab filters by method and transmission status."}]}"""
